∀ {P : Core.Problem} {pieces : CT2.PieceSystem P} {interfaces : CT2.InterfaceSystem pieces}
  (self : CT2.ContextSystem interfaces) {G : P.Ambient} (piece : pieces.Piece G),
  self.glue (self.currentContext piece) (self.abstract piece) = G

∀ {P : Core.Problem} {pieces : CT2.PieceSystem P} {interfaces : CT2.InterfaceSystem pieces}
  {contexts : CT2.ContextSystem interfaces} (self : CT2.ReplacementSystem contexts) {G : P.Ambient}
  (piece : pieces.Piece G) (candidate : self.Candidate piece),
  P.rank (contexts.glue (contexts.currentContext piece) (self.replacement piece candidate)) < P.rank G

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx),
  self.source.graph.Connected

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx),
  (Graph.PackedBoundariedGluing.Piece.pack boundaries self.source).lexRank < Graph.PackedFiniteObject.lexRank ctx.G

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom) (boundary : T),
  Graph.PackedBoundariedGluing.Piece.boundaryDegree boundaries self.piece boundary =
    Graph.PackedBoundariedGluing.Piece.boundaryDegree boundaries atom.source boundary

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom)
  (outside : Graph.PackedBoundariedGluing.Context T),
  input.Target (Graph.PackedBoundariedGluing.glue boundaries self.piece outside) →
    input.Target (Graph.PackedBoundariedGluing.glue boundaries atom.source outside)

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  ¬input.Target (Graph.PackedBoundariedGluing.Piece.pack boundaries self.piece)

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  Graph.PackedBoundariedGluing.Piece.InternalBaseline boundaries input.minimumDegree self.piece

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  self.piece.LexSmaller atom.source
